<template>
  <div
    v-if="showReplyOverlay"
    class="fixed w-full h-full z-10 top-0 left-0 flex items-center justify-center"
  >
    <div
      class="absolute w-full h-full bg-gray-900 opacity-50"
      @click="this.$emit('close')"
    ></div>

    <div
      class="modal-main bg-white mx-auto rounded-lg z-0 overflow-y-auto w-full max-w-lg"
      role="dialog"
      aria-modal="true"
      aria-label="Reply to tweet"
    >
      <div class="pl-1 pr-4 py-1 h-16 border-b-2 border-lightblue">
        <div class="flex flex-row mt-1 ml-4">
          <button
            type="button"
            @click="this.$emit('close')"
            class="rounded-full bg-white p-2 px-3 hover:bg-lightblue flex items-center justify-center"
            aria-label="Close reply"
          >
            <i class="fas fa-times text-blue text-2xl" aria-hidden="true"></i>
          </button>
        </div>
      </div>

      <div
        v-if="profile"
        class="border-l-2 border-r-2 border-white flex flex-col"
      >
        <!-- Original TweetBlock -->
        <div class="p-3 flex flex-row">
          <div class="flex-none mr-4">
            <img
              :src="`${profile.avatar || '/default_profile.png'}`"
              class="h-12 w-12 rounded-full flex-none"

            />
          </div>

          <div class="w-full">
            <div class="flex items-center w-full">
              <p class="font-semibold">{{ tweet.username || 'Anonymous' }}</p>
              <p class="text-sm text-dark ml-2">
                @{{ tweet.user_id }}
              </p>
              <p class="text-sm text-dark ml-2">·</p>
              <p class="text-sm text-dark ml-2">
                {{ $filters.timeago(tweet.created_at) }}
              </p>
            </div>
            <p class="py-2" v-linkify>
              {{ tweet.text }}
            </p>
          </div>
        </div>

        <!-- ReplyBlock -->
        <div v-if="profile.network === 'warpnet'" class="p-3 flex flex-row">
          <div class="flex-none mr-4">
            <img
              :src="`${profile.avatar || '/default_profile.png'}`"
              class="h-12 w-12 rounded-full flex-none"
              alt="User avatar"
            />
          </div>

          <div class="w-full mb-2">
            <form @submit.prevent="sendReply" class="w-full relative">
              <label for="reply-textarea" class="sr-only">Tweet your reply</label>
              <textarea
                id="reply-textarea"
                v-model="text"
                maxlength="280"
                placeholder="Tweet your reply"
                class="w-full focus:outline-none mt-3 pb-3"
              ></textarea>
              <div class="flex items-center">
                <i class="text-lg text-light mr-4 fas fa-film cursor-not-allowed" aria-hidden="true"></i>
                <i class="text-lg text-light mr-4 far fa-chart-bar cursor-not-allowed" aria-hidden="true"></i>
                <i class="text-lg text-light mr-4 far fa-smile cursor-not-allowed" aria-hidden="true"></i>
                <span
                  class="ml-auto text-xs"
                  :class="text.length >= 280 ? 'text-red-600 font-semibold' : (text.length >= 260 ? 'text-yellow-600' : 'text-dark')"
                >{{ text.length }} / 280</span>
              </div>
              <button
                type="submit"
                class="h-10 px-4 text-white font-semibold bg-blue hover:bg-darkblue rounded-full absolute bottom-0 right-0"
                :class="{'opacity-50 cursor-not-allowed': !text.trim() || sending}"
                :disabled="!text.trim() || sending"
              >
                <span v-if="!sending">Reply</span>
                <span v-else><i class="fas fa-circle-notch fa-spin mr-1" aria-hidden="true"></i>Replying…</span>
              </button>
            </form>
          </div>
        </div>
        <div>
          <Tweets :tweets="replies" />
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import {defineAsyncComponent} from "vue";
import {warpnetService} from "@/service/service";
import {toast} from "@/lib/toast";
import {dismissable} from "@/lib/modal.mixin";

export default {
  name: "ReplyOverlay",
  mixins: [dismissable("close")],
  components: {
    Tweets: defineAsyncComponent(() => import('@/components/Tweets.vue'))
  },
  props: ["tweet", "showReplyOverlay", "profile"],
  data() {
    return {
      text: "",
      replies: [],
      sending: false,
    };
  },
  methods: {
    async sendReply() {
      if (this.sending || !this.text.trim()) return;
      this.sending = true;
      try {
        await warpnetService.replyTweet({
          rootId: this.tweet.root_id || this.tweet.id,
          parentId: this.tweet.id,
          parentUserId: this.tweet.user_id,
          text: this.text
        });
        this.$emit('replied');
        this.$emit('close');
      } catch (err) {
        console.error('Failed to send reply:', err);
        toast.error(err?.message || "Couldn't post your reply. Please try again.");
      } finally {
        this.sending = false;
      }
    },
  },
  async created() {
    console.log("loading component:", this.$options.name);
    const root = this.tweet.root_id || this.tweet.id;
    const repliesRequest = {
      rootId: root,
      parentId: this.tweet.id,
      // user_id is the root author only when this tweet is the root itself.
      rootUserId: root === this.tweet.id ? this.tweet.user_id : undefined,
      cursorReset: true,
    }
    let replies = await warpnetService.getReplies(repliesRequest);
    for (const node of replies || []) {
      this.replies.push(node.reply || node);
    }
  },
};
</script>
